// ShareActivity.kt
package com.example.sharehandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.ImageView
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class ShareActivity : AppCompatActivity() {

    private lateinit var textViewSharedContent: TextView
    private lateinit var imageViewSharedImage: ImageView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share)

        textViewSharedContent = findViewById(R.id.textViewSharedContent)
        imageViewSharedImage = findViewById(R.id.imageViewSharedImage)

        handleIncomingIntent(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        intent?.let { handleIncomingIntent(it) }
    }

    private fun handleIncomingIntent(intent: Intent) {
        when (intent.action) {
            Intent.ACTION_SEND -> {
                handleSendIntent(intent)
            }
            Intent.ACTION_SEND_MULTIPLE -> {
                handleSendMultipleIntent(intent)
            }
            else -> {
                Toast.makeText(this, "Unsupported share action", Toast.LENGTH_SHORT).show()
            }
        }
    }

    private fun handleSendIntent(intent: Intent) {
        val type = intent.type

        when {
            type?.startsWith("text/") == true -> {
                handleTextShare(intent)
            }
            type?.startsWith("image/") == true -> {
                handleImageShare(intent)
            }
            else -> {
                Toast.makeText(this, "Unsupported content type", Toast.LENGTH_SHORT).show()
            }
        }
    }

    private fun handleSendMultipleIntent(intent: Intent) {
        val type = intent.type

        when {
            type?.startsWith("image/") == true -> {
                handleMultipleImagesShare(intent)
            }
            else -> {
                Toast.makeText(this, "Multiple items sharing not fully supported", Toast.LENGTH_SHORT).show()
            }
        }
    }

    private fun handleTextShare(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        val sharedSubject = intent.getStringExtra(Intent.EXTRA_SUBJECT)

        if (sharedText != null) {
            val url = extractUrl(sharedText)
            if (url != null) {
                processUrl(url)
                textViewSharedContent.text = "Shared URL:\n$url"
            } else {
                processText(sharedText, sharedSubject)
                textViewSharedContent.text = "Shared Text:\n${sharedSubject ?: ""}\n$sharedText"
            }
            imageViewSharedImage.setImageDrawable(null)
        } else {
            Toast.makeText(this, "No text content found", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleImageShare(intent: Intent) {
        val imageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)

        if (imageUri != null) {
            processImage(imageUri)
            imageViewSharedImage.setImageURI(imageUri)
            textViewSharedContent.text = "Shared Image:\n${imageUri.toString()}"
        } else {
            Toast.makeText(this, "No image content found", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleMultipleImagesShare(intent: Intent) {
        val imageUris = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)

        if (imageUris != null && imageUris.isNotEmpty()) {
            processMultipleImages(imageUris)
            imageViewSharedImage.setImageURI(imageUris[0])
            textViewSharedContent.text = "Shared ${imageUris.size} images:\n${imageUris.joinToString("\n")}"
        } else {
            Toast.makeText(this, "No image content found", Toast.LENGTH_SHORT).show()
        }
    }

    private fun extractUrl(text: String): String? {
        val urlPattern = Regex("https?://[^\\s]+")
        return urlPattern.find(text)?.value
    }

    private fun processUrl(url: String) {
        Toast.makeText(this, "Processing URL: $url", Toast.LENGTH_SHORT).show()
    }

    private fun processText(text: String, subject: String?) {
        Toast.makeText(this, "Processing text: ${subject ?: text.take(20)}", Toast.LENGTH_SHORT).show()
    }

    private fun processImage(imageUri: Uri) {
        Toast.makeText(this, "Processing image: ${imageUri.lastPathSegment}", Toast.LENGTH_SHORT).show()
    }

    private fun processMultipleImages(imageUris: List<Uri>) {
        Toast.makeText(this, "Processing ${imageUris.size} images", Toast.LENGTH_SHORT).show()
    }
}